Do 'LocalCobranca' Do 'Filial' &ResultadoAbertura = DfwOpen(&NomArq,'','', 0, 'ISO-8859-1')
//############################################# Header Label LAYOUT BRADECO ###################################################################################### Do Case Case &BanCod = '237' //BRADESCO &Reg_comeco = '0' // 001 a 001 Identificação do Registro &Reg_comeco += '1' // 002 a 002 Identificação do Arquivo Remessa &Reg_comeco += 'REMESSA' // 003 a 009 Literal Remessa &Reg_comeco += '01' // 010 a 011 Código de Serviço &Reg_comeco += 'COBRANCA' // 012 a 019 Literal Serviço Ident. Por Extenso Tipo Serviço &Reg_comeco += ' ' // 020 a 021 Tipo de Mensagem Identifica Tipo de Mensagem &Reg_comeco += ' ' // 022 a 026 Uso Do Banco Uso Do Banco &Reg_comeco += padL(trim(&CbrNroCon),20,'0') // 027 a 046 CODIGO DA EMPRESA ( Convênio) &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') // 047 a 076 Nome da Empresa &Reg_comeco += '237' // 077 a 079 Número do Bradesco na Câmara de Compensação &Reg_comeco += 'BRADESCO ' // 080 a 094 Nome do Banco por Extenso &Reg_comeco += padL(ToFormattedString(&dia),2,'0')+ padL(ToFormattedString(&mes),2,'0') +trim(ToFormattedString(&ano)) // 095 a 100 Data da Gravação do Arquivo &Reg_comeco += ' ' // 101 a 108 Branco &Reg_comeco += 'MX' // 109 a 110 Identificação do sistema &Reg_comeco += padL(ToFormattedString(&CbrUltRem),7,'0') // 111 a 117 Nº Seqüencial de Remessa &Reg_comeco += space(277) // 118 A 394 Branco &Registro = 1 &Reg_comeco += padL(ToFormattedString(&Registro),6,'0') // 395 a 400 Nº Seqüencial do Registro de Um em Um &Reg_comeco = &Reg_comeco.ToUpper() &ResultadoNext= dfwptxt(&Reg_comeco,400) // Grava Linha &ResultadoNext = dfwnext() // Próxima Linha &RemTxt = &Reg_comeco //############################################# Header Label LAYOUT CRESOL ###################################################################################### Case &BanCod = '133' //CRESOL &Reg_comeco = '0' // 001 a 001 Identificação do Registro &Reg_comeco += '1' // 002 a 002 Identificação do Arquivo Remessa &Reg_comeco += 'REMESSA' // 003 a 009 Literal Remessa &Reg_comeco += '01' // 010 a 011 Código de Serviço &Reg_comeco += 'COBRANCA' // 012 a 019 Literal Serviço Ident. Por Extenso Tipo Serviço &Reg_comeco += ' ' // 020 a 021 Tipo de Mensagem Identifica Tipo de Mensagem &Reg_comeco += ' ' // 022 a 026 Uso Do Banco Uso Do Banco &Reg_comeco += padL(trim(&CbrNroCon),20,'0') // 027 a 046 CODIGO DA EMPRESA ( Convênio) &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') // 047 a 076 Nome da Empresa &Reg_comeco += '133' // 077 a 079 Número do Bradesco na Câmara de Compensação &Reg_comeco += 'CRESOL ' // 080 a 094 Nome do Banco por Extenso &Reg_comeco += ' ' // 095 a 100 Data da Gravação do Arquivo &Reg_comeco += ' ' // 101 a 108 Branco &Reg_comeco += ' ' // 109 a 110 Identificação do sistema &Reg_comeco += space(7) // 111 a 117 Nº Seqüencial de Remessa &Reg_comeco += space(277) // 118 A 394 Branco &Registro = 1 &Reg_comeco += padL(ToFormattedString(&Registro),6,'0') // 395 a 400 Nº Seqüencial do Registro de Um em Um &Reg_comeco = &Reg_comeco.ToUpper() &ResultadoNext= dfwptxt(&Reg_comeco,400) // Grava Linha &ResultadoNext = dfwnext() // Próxima Linha &RemTxt = &Reg_comeco //################################################# LAYOUT BANCO DO BRASIL ################################################################ Case &BanCod = '001' //BANCO DO BRASIL &Reg_comeco = '0' // 001 a 001 Identificação do Registro &Reg_comeco += '1' // 002 a 002 Identificação do Arquivo Remessa &Reg_comeco += 'REMESSA' // 003 a 009 Identificação por Extenso do Tipo de Operação REMESSA / TESTE &Reg_comeco += '01' // 010 a 011 Identificação do Tipo de Serviço: “01” &Reg_comeco += 'COBRANCA' // 012 a 019 Identificação por Extenso do Tipo de Serviço: “COBRANCA” &Reg_comeco += ' ' // 020 a 026 Complemento do Registro: “Brancos” &Reg_Comeco += padL(Substr(trim(&CbrCtaBanAgeCod),1,4),4,'0') // 027 a 030 Prefixo da Agência &Reg_Comeco += padL(Substr(Trim(&CbrCtaBanAgeDig),1,1),1,'0') // 031 a 031 Dígito Verificador - D.V. - do Prefixo da Agência. &Reg_Comeco += padL(Substr(trim(&CbrCtaBanCrt), 1, 8),8,'0') // 032 a 039 Número da Conta Corrente &Reg_Comeco += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') // 040 a 040 Dígito Verificador - D.V. da Conta &Reg_Comeco += '000000' // 041 a 046 Complemento do Registro: “000000” &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') // 047 a 076 Nome do Cedente &Reg_comeco += '001BANCO DO BRASIL' // 077 a 094 001BANCODOBRASIL &Reg_comeco += padL(ToFormattedString(&dia),2,'0')+ padL(ToFormattedString(&mes),2,'0') +trim(ToFormattedString(&ano)) // 095 a 100 Data da Gravação: Informe no formato “DDMMAA” &Reg_comeco += padL(ToFormattedString(&CbrUltRem),7,'0') // 101 a 107 Seqüencial da Remessa &Reg_comeco += space(22) // 108 a 129 Complemento do Registro: “Brancos” &Reg_comeco += padL(trim(&CbrNroCon),7,'0') // 130 a 136 Número do Convênio Líder &Reg_comeco += space(258) // 137 a 394 Complemento do Registro: “Brancos” &Registro = 1 &Reg_comeco += padL(ToFormattedString(&Registro),6,'0') // Seqüencial do Registro:”000001” &Reg_comeco = &Reg_comeco.ToUpper() &ResultadoNext= dfwptxt(&Reg_comeco,400) &ResultadoNext = dfwnext() &RemTxt = &Reg_comeco
//################################################# LAYOUT BANCO SICREDI ################################################################ Case &BanCod = '748' //BANCO SICREDI &Reg_comeco = '0' // 001 a 001 A identicação do header deve ser “0”(zero) &Reg_comeco += '1' // 002 a 002 A identificação do arquivo de remessa deve ser “1”. &Reg_comeco += 'REMESSA' // 003 a 009 “REMESSA” &Reg_comeco += '01' // 010 a 011 O código de serviço de cobrança é “01” &Reg_comeco += padr('COBRANCA',15,' ') // 012 a 026 “COBRANCA” &Reg_comeco += padL(Substr(trim(&CbrNroCon),1,5),5,'0') // 027 a 031 Código do beneficiário - Convênio &Reg_comeco += padL(trim(RetornaSoNumeros.Udp(&CbrCnpj)), 14, '0') // 032 a 045 Informar CPF/CNPJ do beneficiário. Alinhado à direita e zeros à esquerda; &Reg_comeco += space(31) // 046 a 076 Deixar em Brancos (sem preenchimento) &Reg_comeco += '748' // 077 a 079 “748” &Reg_comeco += 'SICREDI ' // 080 a 094 Sicredi” &Reg_comeco += padl(ToFormattedString(&ano4),4,'0') + padl(ToFormattedString(&mes),2,'0') + padL(ToFormattedString(&dia),2,'0') // 095 a 102 Data de gravação do arquivo O Formato da data de geração do arquivo deve estar no padrão: AAAAMMDD &Reg_comeco += space(8) // 103 a 110 Deixar em Branco (sem preenchimento) &Reg_comeco += padl(str(&CbrUltRem), 7, '0') // 111 a 117 Número da remessa Deve ser maior que zero: número do último arquivo remessa + 1; &Reg_comeco += space(273) // 118 a 390 Deixar em Branco (sem preenchimento) &Reg_comeco += '2.00' // 391 a 394 2.00 (o ponto deve ser colocado) &Registro = 1 &Reg_comeco += padL(ToFormattedString(&Registro), 6, '0') // 395 a 400 Número seqüencial do registro &ResultadoNext = dfwptxt(&Reg_comeco,400) &ResultadoNext = dfwnext() &RemTxt = &Reg_comeco
//################################################# LAYOUT BANCO SICOOB ################################################################ Case &BanCod = '756' //BANCO SICOOB
&Reg_comeco = '75600000' // 001 a 001 A identicação do header deve ser “0”(zero) &Reg_comeco += space(9) &Reg_Comeco += '2' // 002 a 003 Tipo de Inscrição do Cedente &Reg_Comeco += padL(trim(RetornaSoNumeros.Udp(&CbrCnpj)),14,'0') // 004 a 017 Número do CPF/CNPJ do Cedente &Reg_comeco += space(20) &Reg_Comeco += padL(Substr(trim(&CbrCtaBanAgeCod),1,5),5,'0') // 027 a 030 Prefixo da Agência &Reg_Comeco += padL(Substr(Trim(&CbrCtaBanAgeDig),1,1),1,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanCrt), 1, 12),12,'0') // 032 a 039 Número da Conta Corrente &Reg_Comeco += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') // 040 a 040 Dígito Verificador - D.V. da Conta &Reg_Comeco += '0' // era espaço mudei pra 0 conforme email no dia 15/06/20 &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') // 047 a 076 Nome do Cedente &Reg_comeco += 'SICOOB ' // 080 a 094 BANCOOBCE” &Reg_comeco += space(10) &Reg_comeco += '1' &Reg_comeco += padl(ToFormattedString(&dia),2,'0') + padl(ToFormattedString(&mes),2,'0') + padL(ToFormattedString(&ano4),4,'0') // 095 a 102 Data de gravação do arquivo O Formato da data de geração do arquivo deve estar no padrão: DDMMAAAA &hora = Time() &Reg_comeco += substr(&hora,1,2)+substr(&hora,4,2)+substr(&hora,7,2) &Reg_comeco += padl(str(&CbrUltRem), 6, '0') // 111 a 117 Número da remessa Deve ser maior que zero: número do último arquivo remessa + 1; &Reg_comeco += '08100000' // 118 a 390 Deixar em Branco (sem preenchimento) &Reg_comeco += space(69)
&ResultadoNext = dfwptxt(&Reg_comeco,240) &ResultadoNext = dfwnext() &RemTxt = &Reg_comeco
//##### Lote &lote = 1 &Reg_comeco = '756' &Reg_comeco += PadL(trim(str(&lote)),4,'0') &Reg_comeco += '1' &Reg_comeco += 'R' &Reg_comeco += '01' &Reg_comeco += ' ' &Reg_comeco += '040' &Reg_comeco += ' ' &Reg_comeco += '2' &Reg_Comeco += padL(trim(RetornaSoNumeros.Udp(&CbrCnpj)),15,'0') &Reg_Comeco += Space(20) &Reg_Comeco += padL(Substr(trim(&CbrCtaBanAgeCod),1,5),5,'0') // 027 a 030 Prefixo da Agência &Reg_Comeco += padL(Substr(Trim(&CbrCtaBanAgeDig),1,1),1,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanCrt), 1, 12),12,'0') // 032 a 039 Número da Conta Corrente &Reg_Comeco += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') &Reg_Comeco += ' ' &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') &Reg_comeco += Space(80) &Reg_comeco += padl(str(&CbrUltRem), 8, '0') &Reg_comeco += padl(ToFormattedString(&dia),2,'0') + padl(ToFormattedString(&mes),2,'0') +padL(ToFormattedString(&ano4),4,'0') &Reg_comeco += '00000000' &Reg_comeco += Space(33)
&ResultadoNext = dfwptxt(&Reg_comeco,240) &ResultadoNext = dfwnext() &RemTxt += NewLine()+&Reg_comeco &SeguimentoP = 0
//################################################# LAYOUT BANCO UNIPRIME ################################################################ Case &BanCod = '099' //BANCO SICOOB
&Reg_comeco = '099' // BANCO &Reg_comeco += '00000' // Fixar ‘9999’ &Reg_comeco += space(9) // Fixar brancos &Reg_Comeco += '2' // 002 a 003 Tipo de Inscrição do singular Fixar ‘2’ &Reg_Comeco += padL(trim(RetornaSoNumeros.Udp(&CbrCnpj)),14,'0') // 004 a 017 Número do CPF/CNPJ do Cedente &Reg_comeco += padL(trim(&CbrNroCon),20,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanAgeCod),1,5),5,'0') // 027 a 030 Prefixo da Agência &Reg_Comeco += padL(Substr(Trim(&CbrCtaBanAgeDig),1,1),1,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanCrt), 1, 12),12,'0') // 032 a 039 Número da Conta Corrente &Reg_Comeco += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') // 040 a 040 Dígito Verificador - D.V. da Conta &Reg_Comeco += ' ' &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') // 047 a 076 Nome do Cedente &Reg_comeco += space(40) &Reg_comeco += '1' &Reg_comeco += space(20) &Reg_comeco += '082' &Reg_comeco += space(74)
&ResultadoNext = dfwptxt(&Reg_comeco,240) &ResultadoNext = dfwnext() &RemTxt = &Reg_comeco
//##### Lote &lote = 1 &Reg_comeco = '099' &Reg_comeco += PadL(trim(str(&lote)),4,'0') &Reg_comeco += '1' &Reg_comeco += 'R' &Reg_comeco += '01' &Reg_comeco += ' ' &Reg_comeco += '041' &Reg_comeco += ' ' &Reg_comeco += '2' &Reg_Comeco += padL(trim(RetornaSoNumeros.Udp(&CbrCnpj)),15,'0') &Reg_comeco += padL(trim(&CbrNroCon),20,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanAgeCod),1,5),5,'0') // 027 a 030 Prefixo da Agência &Reg_Comeco += padL(Substr(Trim(&CbrCtaBanAgeDig),1,1),1,'0') &Reg_Comeco += padL(Substr(trim(&CbrCtaBanCrt), 1, 12),12,'0') // 032 a 039 Número da Conta Corrente &Reg_Comeco += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') &Reg_Comeco += ' ' &AuxCbrRazSoc = RetiraCaracteresEspeciais.Udp(&CbrRazSoc) &Reg_comeco += padR(substr(trim(&AuxCbrRazSoc),1,30),30,' ') &Reg_comeco += Space(88) &Reg_comeco += padl(ToFormattedString(&dia),2,'0') + padl(ToFormattedString(&mes),2,'0') +padL(ToFormattedString(&ano4),4,'0') &Reg_comeco += Space(41)
&ResultadoNext = dfwptxt(&Reg_comeco,240) &ResultadoNext = dfwnext() &RemTxt += NewLine()+&Reg_comeco &SeguimentoP = 0
Otherwise msg('Não localizado o Layout para o banco ' +trim(&BanCod) + ' , Comunique o Suporte Jaspi!') Return EndCase //############################################# Fim Header Label ######################################################################################
//############################################# Registro de Transação - Tipo 1 ###################################################################################### &qtdTitulos = 0 &VlrTotTitulos = 0 For Each Order EmpCod, CreRecPag, CreCbrCod, CreDtaEms,CreDtaVct,CreVlrSdo Where EmpCod = &EmpCod Where CreRecPag = 'R' Where CreCbrCod = &CbrCod Where CreFrpPgtoTip = TipoDuplicata.DUPLICATA Where CreDtaEms >= &DtaIni and CreDtaEms <= &DtaFim Where CreDtaVct >= serverdate() and (CreDtaVct <= &inCreDtaVct or &inCreDtaVct.IsEmpty()) Where CreVlrSdo > 0 // ainda tem vlor a Receber Where (CreSts = &CreSts and CreSts <> Status_Duplicata.CANCELADA) or (&CreSts.IsEmpty() and CreSts <> Status_Duplicata.CANCELADA) //Cancelada Where (CreDtaRet.IsEmpty() or CreDtaRet.IsNull()) when &SemRet = Status_SimNao.Sim &RemFiLCod = FilCod &RemCreSeq = CreCod Do 'AddItemRemessa' //Adiciona Duplicata na Remessa Remessa If CreSts = Status_Duplicata.ATIVO CreSts = Status_Duplicata.EM_REMESSA Endif
&Registro += 1 If CreCliEndCob <> '' Do Case Case &BanCod = '237' //BRADESCO &Detalhe = '1' // 001 a 001 Identificação do Registro &Detalhe += '00000' // 002 a 006 Agência de Débito (opcional) &Detalhe += '0' // 007 a 007 Dígito da Agência de Débito (opcional) &Detalhe += '00000' // 008 a 012 Razão da Conta Corrente (opcional) &Detalhe += '0000000' // 013 a 019 Conta Corrente (opcional) &Detalhe += '0' // 020 a 020 Dígito da Conta Corrente (opcional) //***** Zero, Carteira, Agência e Conta Corrente &Detalhe += '0' // 021 a 021 Identificação da Empresa Beneficiária no Banco &Detalhe += padl(&CbrCarCod,3,'0') // 022 a 024 Código da carteira &Detalhe += padL(Substr(trim(&CbrCtaBanAgeCod),1,5),5,'0')// 025 a 029 Código da Agência Cedente, sem o dígito &Detalhe += padL(Substr(trim(&CbrCtaBanCrt), 1,7),7,'0') // 030 a 036 Conta Corrente &Detalhe += padL(Substr(&CbrCtaBanCrtDig, 1, 1),1,'0') // 037 a 037 Dígito da Conta //******* Uso da Empresa // 038 a 062 Nº Controle do Participante &Detalhe += padL(str(EmpCod),4, '0') // 038 a 041 Empresa Código &Detalhe += padL(str(FilCod),4, '0') // 042 a 045 Filial Código &Detalhe += padl(str(CreCod),8, '0')+space(9) // 046 a 062 Sequência Duplicata + spaço 9 &Detalhe += '000' // 063 a 065 Código do Banco Nº do Banco “237” &Detalhe += &CbrMltVlrVar // 066 a 066 + 067 a 070 (Campo de Multa + Percentual de multa) Se = 2 considerar percentual de multa. Se = 0, sem multa.
// If &CbrTipCob = 'S' //COM REGISTRO? If &CbrBanEnv = 'S' //Banco Envia? Do CAse Case CreBloNro.IsEmpty() and CreCbrImp = TipoImpressao.GerarBoleto // Duplicata Nosso Número &CtaBanNosNro += 1 // Pega o sequecial e soma maisl um no nosso Número GerarNossoNumero.CALL(&BanCod,&CbrNroCon,&CtaBanNosNro,CreDtaEms,&AuxCreBloNro,&Erro) If &Erro = 0 CreBloNro = trim(&AuxCreBloNro) // Atualiza Nosso Número da Duplicata Do 'GravaNossoNumero' EndIf &CreBloNro = trim(&AuxCreBloNro) CalculaDigNosNro.Call(&BanCod,&CbrCarCod,2,&CreBloNro)// Calcula Dígito do Nosso Número &Detalhe += padL(trim(&CreBloNro),12,'0') // 071 a 081 + 082 a 082 Identificação do Título no Banco + Digito de Auto Conferencia do Número Bancário. &Detalhe += '0000000000' // 083 a 092 Desconto Bonificação por dia &Detalhe += '1' // 093 a 093 Condição para Emissão da Papeleta de Cobrança (1 = Banco emite e Processa o registro. 2 = Cliente emite e o Banco somente processa o registro) &Detalhe += 'N' // 094 a 094 Ident. se emite Boleto para Débito Automático (N= Não registra na cobrança. Diferente de N registra e emite Boleto.)
Case not CreBloNro.IsEmpty() &CreBloNro = CreBloNro // Pega Nosso Número da Duplicata CalculaDigNosNro.Call(&BanCod,&CbrCarCod,2,&CreBloNro)// Calcula Dígito do Nosso Número &Detalhe += padL(trim(&CreBloNro),12,'0') // 071 a 081 + 082 a 082 Identificação do Título no Banco + Digito de Auto Conferencia do Número Bancário. &Detalhe += '0000000000' // 083 a 092 Desconto Bonificação por dia &Detalhe += '1' // 093 a 093 Condição para Emissão da Papeleta de Cobrança (1 = Banco emite e Processa o registro. 2 = Cliente emite e o Banco somente processa o registro) &Detalhe += 'N' // 094 a 094 Ident. se emite Boleto para Débito Automático (N= Não registra na cobrança. Diferente de N registra e emite Boleto.)
Otherwise
&Detalhe += '000000000000' // 071 a 081 + 082 a 082 Identificação do Título no Banco + Digito de Auto Conferencia do Número Bancário. &Detalhe += '0000000000' // 083 a 092 Desconto Bonificação por dia &Detalhe += '1' // 093 a 093 Condição para Emissão da Papeleta de Cobrança (1 = Banco emite e Processa o registro. 2 = Cliente emite e o Banco somente processa o registro) &Detalhe += 'N' // 094 a 094 Ident. se emite Boleto para Débito Automático (N= Não registra na cobrança. Diferente de N registra e emite Boleto.) EndCAse
