&Detalhe += Space(110) &Detalhe += '00000000' &Detalhe += '000' &Detalhe += '00000' &Detalhe += ' ' &Detalhe += '000000000000' &Detalhe += ' ' &Detalhe += ' ' &Detalhe += '0' &Detalhe += Space(9) &Detalhe = &Detalhe.ToUpper() &ResultadoNext= dfwptxt(&Detalhe,240) &RemTxt += NewLine()+&Detalhe &ResultadoNext = dfwnext() //### FIM - Seguimento R
