msg('Arquivo gerado! Faça o download do arquivo.') //###############################################################FINAL DO ARQUIVO ########################################
Sub 'LocalCobranca' For each Order EmpCod,CbrCod,CbrTipImp Where EmpCod = &Context.EmpCod Where CbrCod = &CbrCod Where CbrTipImp = TipoImpressao.GerarBoleto //Gerar Boleto
&CbrNroCon = CbrNroCon // Local Cobrança Número Convênio &CbrNroConDig = CbrNroConDig // Local Cobrança Número Digito Convênio &CbrMltVlr = CbrMltVlr // Local Cobrança % de Multa &BanCod = CbrCtaBanBanCod // Local Cobrança Banco Código &CtaBanNosNro = CtaBanNosNro // Local Cobrança Nosso Número &CbrTipImp = CbrTipImp // Local Cobrança Tipo de Impressão &CbrCtaBanAgeCod = CbrCtaBanAgeCod // Local Cobrança Agência Código &CbrCtaBanAgeDig = CbrCtaBanAgeDig // Local Cobrança Agência Dígito &CbrCtaBanCrt = CbrCtaBanCrt // Local Cobrança Nro da Conta &CbrCtaBanCrtDig = CbrCtaBanCrtDig // Local Cobrança Dígito Conta Corrente &CbrCarCod = CbrCarCod // Local Cobrança Carteira &CbrCarVar = CbrCarVar // Local Cobrança Variação // &CbrTipCob = CbrTipCob // Local Cobrança Tipo Cobrança Com/Sem Registro &CbrUltRem = CbrUltRem + 1 // Local Cobrança Ultima Remessa &CbrRazSoc = CbrRazSoc // Local Cobrança Baneficiário &CbrCNPJ = CbrCnpj // Local Cobrança Beneficiário CNPJ &CbrBanEnv = CbrBanEnv // Local Cobrança Banco Envia Boleto // &CbrTipCob = CbrTipCob // Local Cobrança Com Registro? &CbrProAut = CbrProAut // Local Cobrança Protesta Automaticamente? &CbrProQtd = CbrProQtd // Quantos dias para o protesto &CbrDesAnt = CbrDesAnt // Percentual de desconto para pagamento antecipado &CbrDesDia = CbrDesDia // Percentual de Desconto para pagemento em dia. &CbrQtdDiaDesc = CbrQtdDiaDesc //QTD DIAS Data Limite Desconto &CbrInsBol1 = CbrInsBol1 &CbrBolMod = CbrBolMod // Modelo Boleto &CbrIns1 = CbrIns1 // Instrução 1 Códificada Arquivo de Cobrança &CbrIns2 = CbrIns2 // Instrução 1 Códificada Arquivo de Cobrança &CbrAvaCnpj = CbrAvaCnpj &CbrAvaRaz = CbrAvaRaz
//Config Multa If CbrMltVlr > 0 &CbrMltVlrVar = '2'+padL(str(CbrMltVlr*100),4,'0') Else &CbrMltVlrVar = '00000' EndIf
//Config Protesto If CbrProAut = 'S' &CbrIns1 = '06' //(Protestar). &CbrIns2 = padL(str(CbrProQtd),2,'0') Else &CbrIns1 = CbrIns1 &CbrIns2 = CbrIns2 EndIF &CbrJurCod = CbrJurCod // Local Cobrança Juros Código &JurTaxDia = 0 Do 'Juros'
//############################# NOME DO ARQUIVO ########################################### &hoje = ServerDate() &dia = day(&hoje) &mes = Month(&hoje) &ano = Year(&hoje) - 2000 &Ano4 = Year(&hoje) Do Case Case CbrCtaBanBanCod = '237' //BRADESCO &NumArq = 1 Do while &NumArq <= 99 &RemNomArq = 'CB'+padL(Str(&dia),2,'0')+padL(str(&mes),2,'0')+Padl(ToFormattedString(&NumArq),2,'0')+'.rem' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&RemNomArq.Trim() &Existe = fileexist(&NomArq) If &existe = 0 &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+ &RemNomArq.Trim() Exit EndIf &NumArq += 1 EndDo
Case CbrCtaBanBanCod = '133' //cresol &NumArq = 1 Do while &NumArq <= 99 &RemNomArq = 'CB'+padL(Str(&dia),2,'0')+padL(str(&mes),2,'0')+Padl(ToFormattedString(&NumArq),2,'0')+'.rem' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&RemNomArq.Trim() &Existe = fileexist(&NomArq) If &existe = 0 &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+ &RemNomArq.Trim() Exit EndIf &NumArq += 1 EndDo Case CbrCtaBanBanCod = '001' //BANCO DO BRASIL &NumArq = 641 &RemNomArq = 'CBR'+padL(trim(str(&NumArq)),3,'0')+'.REM' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+ &RemNomArq.Trim() &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+ &RemNomArq.Trim() Case CbrCtaBanBanCod = '748' //SICREDI &NumArq = 1 &auxnomArq = '' Do while &NumArq <= 99 Do Case Case &mes = 10 &auxnomArq = padL(trim(&CbrNroCon),5, '0') +'O'+padL(Str(&dia),2,'0') Case &mes = 11 &auxnomArq = padL(trim(&CbrNroCon),5, '0')+'N'+padL(Str(&dia),2,'0') Case &mes = 12 &auxnomArq = padL(trim(&CbrNroCon),5, '0')+'D'+padL(Str(&dia),2,'0') Otherwise &auxnomArq = padL(trim(&CbrNroCon),5, '0')+trim(str(&mes))+padL(Str(&dia),2,'0') EndCase
IF &NumArq = 1 &RemNomArq = &auxnomArq.trim()+'.CRM' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&auxnomArq.trim()+'.CRM' &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+&auxnomArq.trim()+'.CRM' ELSE &RemNomArq = &auxnomArq.trim()+'.RM'+trim(str(&NumArq)) &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&auxnomArq.trim()+'.RM'+trim(str(&NumArq)) &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+&auxnomArq.trim()+'.RM'+trim(str(&NumArq)) EndIf
&Existe = fileexist(&NomArq) If &existe = 0 exit EndIf &NumArq += 1 EndDo Case CbrCtaBanBanCod = '756' &NumArq = 1 Do while &NumArq <= 99 &RemNomArq = 'COB'+padL(Str(&dia),2,'0')+padL(str(&mes),2,'0')+Padl(ToFormattedString(&NumArq),2,'0')+'.rem' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&RemNomArq.Trim() &Existe = fileexist(&NomArq) If &existe = 0 &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+ &RemNomArq.Trim() Exit EndIf &NumArq += 1 EndDo
Case CbrCtaBanBanCod = '099' &NumArq = 1 Do while &NumArq <= 99 &RemNomArq = 'Remessa099_'+trim(str(&NumArq))+'.rem' &nomArq = &SdtConfiguracoesPasta.PastaDiretorioCobFis+&RemNomArq.Trim() &Existe = fileexist(&NomArq) If &existe = 0 &link = &SdtConfiguracoesPasta.PastaDiretorioCobVir+ &RemNomArq.Trim() Exit EndIf &NumArq += 1 EndDo EndCase
EndFor Do 'CapaRemessa' Do 'GravaSequencial' EndSub
Sub 'Juros' For each Order EmpCod,JurCod,(JurAno),(JurMes) Where EmpCod = &Context.EmpCod Where JurCod = &CbrJurCod &JurTax = JurTax &JurTaxDia = JurTaxDia Exit EndFor EndSub
Sub 'CapaRemessa' For Each Order EmpCod,RemCbrCod, RemNum Where EmpCod = &Context.EmpCod Where RemCbrCod = &CbrCod Where RemNum = &CbrUltRem
For Each Order EmpCod,RemCbrCod, RemNum, RemItm Delete EndFor Delete EndFor
New EmpCod = &Context.EmpCod RemCbrCod = &CbrCod RemNum = &CbrUltRem RemBanCod = &BanCod RemDta = serverdate() RemHor = ServerNow() RemNomArq = &RemNomArq EndNEw EndSub
Sub 'AddItemRemessa' For Each Order EmpCod,RemCbrCod, RemNum, (RemItm) Where EmpCod = &Context.EmpCod Where RemCbrCod = &CbrCod Where RemNum = &CbrUltRem &RemItm = RemItm Exit EndFor &RemItm += 1
For Each Order EmpCod,RemFilCod,RemCreSeq,RemCbrCod, RemNum, (RemItm) Where EmpCod = &Context.EmpCod Where RemCbrCod = &CbrCod Where RemNum = &CbrUltRem Where RemFilCod = &FilCod Where RemCreSeq = &CreSeq Exit When none New EmpCod = &EmpCod RemCbrCod = &CbrCod RemNum = &CbrUltRem RemItm = &RemItm RemFilCod = &RemFiLCod RemCreSeq = &RemCreSeq EndNEw EndFor EndSub
Sub 'Filial' For each Order EmpCod,FilCod Where EmpCod = &EmpCod Where FilCod = &FilCod &FilRaz = FilRaz Exit EndFor EndSub
Sub 'GravaNossoNumero' For each Order EmpCod,CbrCod,CbrTipImp Where EmpCod = &EmpCod Where CbrCod = &CbrCod Where CbrTipImp = TipoImpressao.GerarBoleto //Gerar Boleto CtaBanNosNro = &CtaBanNosNro Exit EndFor EndSub
Sub 'GravaSequencial' For each Order EmpCod,CtaBanCrt Where EmpCod = &EmpCod Where Trim(CtaBanCrt) = trim(&CbrCtaBanCrt) &CtaBanCod = CtabanCod For each Order EmpCod,CbrCtaBanCod Where EmpCod = &EmpCod Where CbrCtaBanCod = &CtaBanCod CbrUltRem = &CbrUltRem EndFor EndFor EndSub
Sub 'GravaArquivoBanco' For Each Order EmpCod,RemCbrCod, RemNum Where EmpCod = &Context.EmpCod Where RemCbrCod = &CbrCod Where RemNum = &CbrUltRem RemTxt = &RemTxt Exit EndFor EndSub
